  candidate_name: parsed.candidate_name || formData.full_name || '',
  experience_level: parsed.experience_level || userExpLevel,
  years_of_experience: parsed.years_of_experience ?? 0,
  key_skills: parsed.key_skills || [],
  soft_skills: parsed.soft_skills || [],
  domains: parsed.domains || [],
  education: parsed.education || '',
  notable_projects: parsed.notable_projects || [],
  certifications: parsed.certifications || [],
  preferred_job_titles: (parsed.preferred_job_titles && parsed.preferred_job_titles.length > 0)
    ? parsed.preferred_job_titles
    : [userTargetJob],
  strengths: parsed.strengths || [],
  weaknesses: parsed.weaknesses || [],
  recommended_keywords: parsed.recommended_keywords || []
};

return [{
  json: {
    candidate_profile: profile,
    resume_text: formData.resume_text || '',
    target_location: userLocation,
    target_job: userTargetJob,
    email: formData.email || '',
    full_name: formData.full_name || ''
  }
}];

