const allItems = $input.all();
const allJobs = [];
const seen = new Set();

const prevData = {
  candidate_profile: $('Parse Job Titles').first().json.candidate_profile,
  resume_text: $('Parse Job Titles').first().json.resume_text,
  target_location: $('Parse Job Titles').first().json.target_location,
  target_job: $('Parse Job Titles').first().json.target_job,
  email: $('Parse Job Titles').first().json.email,
  full_name: $('Parse Job Titles').first().json.full_name,
  cv_improvement: $('Parse CV Improvement').first().json.cv_improvement
};

for (const item of allItems) {
  const jobs = item.json.jobs_results || [];
  for (const job of jobs) {
    const key = job.job_id || (job.title + job.company_name);
    if (!seen.has(key)) {
      seen.add(key);
      allJobs.push(job);
    }
  }
}

if (allJobs.length === 0) {
  return [{ json: { ...prevData, no_jobs: true } }];
}

return allJobs.slice(0, 30).map(job => ({
  json: { ...job, ...prevData }
}));

const data = $input.first().json;
const targetJob = data.target_job || '';
const location = data.target_location || 'Indonesia';
const titles = data.candidate_profile?.preferred_job_titles || [];

const queries = [
  `${targetJob} ${location}`,
  `${titles[1] || targetJob} ${location}`,
  `${titles[2] || targetJob} ${location}`,
  `${titles[3] || targetJob} ${location}`,
  `${titles[4] || 'lowongan ' + targetJob} ${location}`
];

const unique = [...new Set(queries.map(q => q.trim()))];

return unique.map(q => ({
  json: { ...data, search_query: q }
}));
